// Number of species the NN was trained on.
// CodeJeNN will regenerate this value.
const int n_species_diff = 9;

// Species name table (must match the order in thermophysicalProperties).
// CodeJeNN will regenerate this list.
static constexpr std::array<const char*, n_species_diff> species_names_diff_gen()
{
    return {"H", "H2", "O", "O2", "OH", "H2O", "HO2", "H2O2", "AR"};
}

static std::string species_name_diff_gen(int index)
{
    constexpr auto names = species_names_diff_gen();
    return names[index];
}

// ----------------------------------------------------------
// Activation functions — CodeJeNN will regenerate these.
// ----------------------------------------------------------
template<typename Scalar>
void relu_diff(Scalar* outputs, const Scalar* inputs, size_t size) noexcept
{
    for (size_t i = 0; i < size; ++i)
        outputs[i] = inputs[i] > Scalar(0) ? inputs[i] : Scalar(0);
}

template<typename Scalar>
void linear_diff(Scalar* outputs, const Scalar* inputs, size_t size) noexcept
{
    for (size_t i = 0; i < size; ++i)
        outputs[i] = inputs[i];
}

// ----------------------------------------------------------
// predict_diffusion
//
// Input layout  (size = n_species_diff + 2):
//   [0]      T          (K)
//   [1]      p/101325   (atm)
//   [2..n+1] Y_i        (mass fractions, i = 0..n_species_diff-1)
//
// Output (size = n_species_diff):
//   Diff_i  (m^2/s, mixture-averaged diffusion coefficient)
//
// STUB: replace everything below with the CodeJeNN-generated
//       network (weight arrays + forward-pass calls).
// ----------------------------------------------------------
inline std::array<scalar, n_species_diff>
predict_diffusion(const std::array<scalar, n_species_diff + 2>& input)
{
    std::array<scalar, n_species_diff> output;
    for (int i = 0; i < n_species_diff; ++i)
        output[i] = scalar(1e-5);   // placeholder: 1e-5 m^2/s
    return output;
}
